#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e5+5;
int n,x0,x[MAXN];
int main(void){
	// freopen("vis.in","r",stdin);
