   	for(int i=1;i<=n;++i) cin>>x[i];
    if(n==1){puts("0");exit(false);}
    sort(x+1,x+1+n);
    cout<<min((ll)(min(abs(x[n]-x0)+abs(x[n]-x[2]),abs(x[n-1]-x0)+abs(x[n-1]-x[1]))),(ll)(min(abs(x[1]-x0)+abs(x[1]-x[n-1]),abs(x[2]-x0)+abs(x[n]-x[2]))));
	return false;
}
